import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
    iconBgGradient: "linear-gradient(135deg, #667eea, #764ba2)",
    iconColor: "#fff",
    contentBgGradient: "linear-gradient(135deg, #764ba2, #667eea)",
    arrowBorderColor: "#764ba2",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaCloud />,
    iconBgGradient: "linear-gradient(135deg, #43cea2, #185a9d)",
    iconColor: "#fff",
    contentBgGradient: "linear-gradient(135deg, #185a9d, #43cea2)",
    arrowBorderColor: "#185a9d",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaUniversity />,
    iconBgColor: "#ff7e5f",
    iconColor: "#fff",
    contentBgColor: "#feb47b",
    arrowBorderColor: "#ff7e5f",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaUniversity />,
    iconBgColor: "#f7971e",
    iconColor: "#fff",
    contentBgColor: "#ffd200",
    arrowBorderColor: "#f7971e",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #11998e, #38ef7d)",
    iconColor: "#fff",
    contentBgGradient: "linear-gradient(135deg, #38ef7d, #11998e)",
    arrowBorderColor: "#11998e",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaUniversity />,
    iconBgColor: "#6a11cb",
    iconColor: "#fff",
    contentBgColor: "#2575fc",
    arrowBorderColor: "#6a11cb",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #0f2027, #203a43, #2c5364)",
    iconColor: "#fff",
    contentBgGradient: "linear-gradient(135deg, #2c5364, #203a43, #0f2027)",
    arrowBorderColor: "#203a43",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021 - 2021",
    icon: <FaUniversity />,
    iconBgColor: "#0078d4",
    iconColor: "#fff",
    contentBgColor: "#00a4ef",
    arrowBorderColor: "#0078d4",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019 - 2019",
    icon: <FaUniversity />,
    iconBgGradient: "linear-gradient(135deg, #ff6a00, #ee0979)",
    iconColor: "#fff",
    contentBgGradient: "linear-gradient(135deg, #ee0979, #ff6a00)",
    arrowBorderColor: "#ee0979",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
    iconBgColor: "#c1464eff",
    iconColor: "#fff",
    contentBgColor: "#9b2c2c",
    arrowBorderColor: "#c1464eff",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
    iconBgColor: "#1e40af",
    iconColor: "#fff",
    contentBgColor: "#3b82f6",
    arrowBorderColor: "#3b82f6",
  },
];

export default function ExperienceTimeline() {
  return (
    <VerticalTimeline>
      {experienceData.map((exp, idx) => (
        <VerticalTimelineElement
          key={idx}
          date={<span style={{ fontWeight: "bold", color: exp.iconBgColor || "#6b46c1" }}>{exp.date}</span>}
          iconStyle={{
            background: exp.iconBgGradient || exp.iconBgColor || "#6b46c1",
            color: exp.iconColor || "#fff",
            boxShadow: "0 0 10px rgba(0,0,0,0.2)",
          }}
          contentStyle={{
            background: exp.contentBgGradient || exp.contentBgColor || "#6b46c1",
            color: "#fff",
            boxShadow: "0 4px 15px rgba(0,0,0,0.15)",
          }}
          contentArrowStyle={{
            borderRight: `7px solid ${exp.arrowBorderColor || "#6b46c1"}`,
          }}
          icon={exp.icon}
        >
          <h3>{exp.title}</h3>
          <h4>{exp.company}</h4>
          <p>{exp.description}</p>
        </VerticalTimelineElement>
      ))}
    </VerticalTimeline>
  );
}
